code.Python3:
import sys
def main():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx=0
    T=int(data[idx]);idx+=1
    out=[]
    for _ in range(T):
        N=int(data[idx]);idx+=1
        seen=set()
        for _ in range(N):
            task=int(data[idx]);idx+=1
            if task not in seen:
                seen.add(task)
                out.append(str(task))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()

