const fs=require('fs');
const lines=fs.readFileSync(0,'utf-8').trim().split(/\n/);
let idx=0;
if(lines.length===0) process.exit(0);
const T=parseInt(lines[idx].trim(),10);
idx++;
let result=[];
for(let t=0;t<T;++t){
  const N=parseInt(lines[idx].trim(),10);
  idx++;
  const seen=new Set();
  for(let i=0;i<N;++i){
    const task=parseInt(lines[idx].trim(),10);
    idx++;
    if(!seen.has(task)){
      seen.add(task);
      result.push(task);
    }
  }
}
